/* Generated by hand for ResourcePanel.SC2Layout */
#ifndef SC2_RESOURCE_PANEL_H
#define SC2_RESOURCE_PANEL_H

#include "games/starcraft-2/common/stb_sc2layout.h"

typedef struct ResourcePanel_s {
    LPSC2FRAMEDEF ResourcePanelFrame;
    LPSC2FRAMEDEF MineralsIcon;
    LPSC2FRAMEDEF MineralsText;
    LPSC2FRAMEDEF GasIcon;
    LPSC2FRAMEDEF GasText;
    LPSC2FRAMEDEF SupplyIcon;
    LPSC2FRAMEDEF SupplyText;
    LPSC2FRAMEDEF SupplyMaxText;
} ResourcePanel_t;

static inline BOOL ResourcePanel_Bind(ResourcePanel_t *out, LPSC2FRAMEDEF bind_root) {
    BOOL ok = true;
    if (!out) return false;
    memset(out, 0, sizeof(*out));
    out->ResourcePanelFrame = bind_root;
    if (!out->ResourcePanelFrame) { BZ_SC2_REPORT_MISSING("ResourcePanelFrame"); ok = false; }
    BZ_SC2_BIND_CHILD(out, MineralsIcon, bind_root, "MineralsIcon");
    BZ_SC2_BIND_CHILD(out, MineralsText, bind_root, "MineralsText");
    BZ_SC2_BIND_CHILD(out, GasIcon, bind_root, "GasIcon");
    BZ_SC2_BIND_CHILD(out, GasText, bind_root, "GasText");
    BZ_SC2_BIND_CHILD(out, SupplyIcon, bind_root, "SupplyIcon");
    BZ_SC2_BIND_CHILD(out, SupplyText, bind_root, "SupplyText");
    BZ_SC2_BIND_CHILD(out, SupplyMaxText, bind_root, "SupplyMaxText");
    return ok;
}

static inline BOOL ResourcePanel_Load(ResourcePanel_t *out) {
    return out &&
           SC2_EnsureLayout("UI/Layout/UI/ResourcePanel.SC2Layout") &&
           ResourcePanel_Bind(out, SC2_FindFrame("ResourcePanelFrame"));
}

#endif /* SC2_RESOURCE_PANEL_H */
